import{_ as a,o as t,c as s,a0 as o}from"./chunks/framework.Dxq5Kom6.js";const n="/images/hub_add_analysis_from_proposal.png",u=JSON.parse('{"title":"Analyses","description":"","frontmatter":{},"headers":[],"relativePath":"guide/user/analyses.md","filePath":"guide/user/analyses.md"}'),i={name:"guide/user/analyses.md"};function d(r,e,l,c,p,h){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="analyses" tabindex="-1">Analyses <a class="header-anchor" href="#analyses" aria-label="Permalink to &quot;Analyses&quot;">​</a></h1><p>Analyses are distributed computations within a <a href="/guide/user/projects.html">project</a>. They define the code, configuration, and target nodes for a federated computation.</p><h2 id="creating-an-analysis" tabindex="-1">Creating an Analysis <a class="header-anchor" href="#creating-an-analysis" aria-label="Permalink to &quot;Creating an Analysis&quot;">​</a></h2><p><img src="'+n+'" alt="Add analysis from project"></p><p>An analysis requires:</p><ul><li>A parent <strong>project</strong> (must be approved)</li><li>A <strong>master image</strong> — the base Docker image for execution</li><li><strong>Analysis code</strong> — uploaded to a storage bucket and built into a container</li></ul><h3 id="naming" tabindex="-1">Naming <a class="header-anchor" href="#naming" aria-label="Permalink to &quot;Naming&quot;">​</a></h3><p>Every analysis has two name fields:</p><ul><li><strong><code>name</code></strong> — a URL-friendly identifier (lowercase letters, digits and the characters <code>-</code>, <code>_</code>, <code>.</code>; no whitespace). It is <strong>required</strong>. If you do not provide one when creating an analysis, a readable name is <strong>generated automatically</strong> (e.g. <code>brave-otter-1a2b3c</code>). The create form also pre-fills an editable suggestion.</li><li><strong><code>display_name</code></strong> — an optional, free-form human-readable label. When set, it is shown in the UI in place of the <code>name</code>.</li></ul><p>The opaque analysis id (UUID) is no longer surfaced in list views or page headlines — analyses are identified by their <code>display_name</code> (falling back to <code>name</code>).</p><h3 id="node-assignment" tabindex="-1">Node Assignment <a class="header-anchor" href="#node-assignment" aria-label="Permalink to &quot;Node Assignment&quot;">​</a></h3><p>When an analysis is created, every <strong>approved</strong> node of its parent project is automatically assigned to it (as an <code>AnalysisNode</code>). Project nodes that are still pending project approval are skipped — once approved, they can be assigned manually.</p><p>Auto-assignment does not bypass the <a href="/guide/user/approval.html">per-analysis approval</a> step: each assigned node still carries its own approval decision. Aggregator nodes are approved automatically, while default nodes start pending and must be approved by the node&#39;s realm authority before the analysis can be locked.</p><p>You can still add or remove nodes afterwards. Re-assigning a node that is already attached to the analysis updates the existing assignment instead of failing, so manual selection and auto-assignment coexist safely.</p><h2 id="execution-flow" tabindex="-1">Execution Flow <a class="header-anchor" href="#execution-flow" aria-label="Permalink to &quot;Execution Flow&quot;">​</a></h2><p>Once <a href="/guide/user/approval.html">approved</a>, an analysis goes through:</p><ol><li><strong>Configuration</strong> — storage buckets are provisioned, configuration is locked</li><li><strong>Build</strong> — the worker builds a Docker image from the analysis code and master image</li><li><strong>Distribute</strong> — the container image is pushed to target node registries</li><li><strong>Execute</strong> — nodes pull and run the container against their local data</li><li><strong>Complete</strong> — results are collected and stored</li></ol><h2 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to &quot;API Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/analyses</code></td><td>List analyses</td></tr><tr><td><code>POST</code></td><td><code>/analyses</code></td><td>Create analysis</td></tr><tr><td><code>GET</code></td><td><code>/analyses/:id</code></td><td>Get analysis details</td></tr><tr><td><code>PUT</code></td><td><code>/analyses/:id</code></td><td>Update analysis</td></tr><tr><td><code>DELETE</code></td><td><code>/analyses/:id</code></td><td>Delete analysis</td></tr><tr><td><code>GET</code></td><td><code>/analysis-buckets</code></td><td>List analysis storage buckets</td></tr><tr><td><code>GET</code></td><td><code>/analysis-bucket-files</code></td><td>List analysis bucket files</td></tr></tbody></table><h2 id="analysis-buckets" tabindex="-1">Analysis Buckets <a class="header-anchor" href="#analysis-buckets" aria-label="Permalink to &quot;Analysis Buckets&quot;">​</a></h2><p>Each analysis can have associated storage buckets for input data, code, and results. Buckets are managed by the <a href="/reference/storage/">Storage service</a> and provisioned automatically during the configuration phase.</p>',21)])])}const y=a(i,[["render",d]]);export{u as __pageData,y as default};
